210	\section{Curves and the canonical sheaf}
211	
212	The case of a smooth proper curve $C \to \Spec k$ is the special case $n = 1$: the relative cotangent sheaf $\Omega_{C/k}$ is a line bundle on $C$, classically denoted $\omega_C$ and called the \emph{canonical sheaf}.
213	
214	\begin{theorem}\leanok
215	[Serre-duality genus equality]
216	  \label{thm:serre_duality_genus}
217	  \lean{AlgebraicGeometry.Scheme.serre_duality_genus}
218	  \uses{def:relative_kaehler_sheaf}
219	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. Then
220	  \[
221	    \dim_k H^0(C, \Omega_{C/k}) \;=\; \dim_k H^1(C, \struct{C}).
222	  \]
223	  Both sides equal the genus $g(C)$. The equality is the dimension one case of Serre duality applied to the canonical sheaf; combined with the definition $g(C) = \dim_k H^1(C, \struct{C})$, this provides the alternative differential-theoretic characterisation used when computing the relative dimension of $\Jac(C)$ at the identity.
224	\end{theorem}
