70	\begin{definition}\leanok
71	[Universal derivation]
72	  \label{def:universal_derivation}
73	  \lean{AlgebraicGeometry.Scheme.universalDerivation}
74	  \uses{def:relative_kaehler_sheaf}
75	  The morphism of sheaves of abelian groups $\mathrm{d} \colon \struct{X} \to \Omega_{X/S}$, defined on each affine open $V = \Spec B$ over $\Spec A$ by the Mathlib universal derivation $\mathrm{d}_{B/A} \colon B \to \Omega_{B/A}$, is the \emph{universal derivation}. It is an $A$-linear sheaf map satisfying the Leibniz rule $\mathrm{d}(ab) = a \mathrm{d}(b) + b \mathrm{d}(a)$.
76	\end{definition}
