80	\begin{definition}\leanok
81	[Base-change cotangent map $\alpha$]
82	  \label{def:cotangent_alpha}
83	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqAlpha}
84	  \uses{def:relative_kaehler_sheaf}
85	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{base-change cotangent map} is the natural morphism of quasi-coherent $\struct{X}$-modules
86	  \[
87	    \alpha \colon f^*\Omega_{Y/S} \;\longrightarrow\; \Omega_{X/S}
88	  \]
89	  whose local description on an affine chart with rings $A = \struct{S}(W)$, $A' = \struct{Y}(f(V))$, $B = \struct{X}(V)$ is the standard map $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A}$ of K\"ahler differentials, $da \otimes b \mapsto b \cdot da$.
90	\end{definition}
