92	\begin{definition}\leanok
93	[Relative-quotient cotangent map $\beta$]
94	  \label{def:cotangent_beta}
95	  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta}
96	  \uses{def:relative_kaehler_sheaf}
97	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{relative-quotient cotangent map} is the natural surjection of quasi-coherent $\struct{X}$-modules
98	  \[
